    try {
        return acksString.trim().equalsIgnoreCase("all") ? "-1" : Short.parseShort(acksString.trim()) + "";
    } catch (NumberFormatException e) {
        throw new ConfigException("Invalid configuration value for 'acks': " + acksString);
    }
}

